// --- PREMIER NOEUD : 1. Préparer les Paramètres ---
const items = $input.all();
const item = items[0]?.json || {};
const body = item.body || item;

const isWebhook = item.body !== undefined;

// 1. ON RÉCUPÈRE L'ID ENVOYÉ PAR FLASK ICI
const scan_id = body.scan_id || "manual-" + new Date().getTime(); 

const network = body['network'] 
  || body['target']
  || body['Cible réseau (IP ou domaine)'] 
  || 'scanme.nmap.org';

const emailTo = body['email']
  || body['Email destinataire du rapport']
  || "security@example.com";

const portRange = body['portRange']
  || body['ports']
  || '22,80,443,8080';

const timestamp = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);

return [{
  json: {
    scan_id,      // <--- TRÈS IMPORTANT : On l'ajoute au résultat
    network,
    emailTo,
    portRange,
    timestamp,
    tempDir: '/tmp/vulnscan',
    source: isWebhook ? 'webhook' : 'scheduler'
  }
}];

const nmapData = $input.first().json;
let raw = nmapData.stdout || '{"host":[]}';

// Si raw est déjà un objet, on le garde, sinon on le parse
let parsed;
if (typeof raw === 'string') {
    try {
        parsed = JSON.parse(raw);
    } catch (e) {
        parsed = { host: [] };
    }
} else {
    parsed = raw;
}

const hosts = parsed.host || [];
const network = $('1. Préparer les Paramètres').first().json.network;
const timestamp = $('1. Préparer les Paramètres').first().json.timestamp;
const tempDir = $('1. Préparer les Paramètres').first().json.tempDir;

const openPorts = [];

// Parcourir les hosts
for (let i = 0; i < hosts.length; i++) {
    const host = hosts[i];

    // Vérifier si host existe
    if (!host) continue;

    // Accéder aux ports de façon sécurisée
    const portsObj = host.ports || {};
    const portList = portsObj.port || [];

    for (let j = 0; j < portList.length; j++) {
        const port = portList[j];
        if (port && port.portid) {
            openPorts.push(parseInt(port.portid, 10));
        }
    }
}

console.log('Open ports:', JSON.stringify(openPorts));

// Déterminer les ports HTTP/HTTPS
let hasHTTP = false;
let hasHTTPS = false;
let httpPort = 80;
let httpsPort = 443;

const httpPorts = [80, 8080, 8000, 8888, 3000, 5000];
const httpsPorts = [443, 8443, 4443, 8443];

for (let k = 0; k < openPorts.length; k++) {
    const port = openPorts[k];

    if (httpPorts.includes(port)) {
        hasHTTP = true;
        httpPort = port;
    }
    if (httpsPorts.includes(port)) {
        hasHTTPS = true;
        httpsPort = port;
    }
}

// Vérifier aussi dans les services détectés pour plus de précision
for (let i = 0; i < hosts.length; i++) {
    const host = hosts[i];
    if (!host || !host.ports || !host.ports.port) continue;

    for (let j = 0; j < host.ports.port.length; j++) {
        const port = host.ports.port[j];
        if (!port || !port.service) continue;

        const serviceName = (port.service.name || '').toLowerCase();
        const portNum = parseInt(port.portid, 10);

        if (serviceName.includes('http') && !serviceName.includes('https')) {
            hasHTTP = true;
            httpPort = portNum;
        }
        if (serviceName.includes('https') || serviceName.includes('ssl')) {
            hasHTTPS = true;
            httpsPort = portNum;
        }
    }
}

console.log('hasHTTP:', hasHTTP, '| hasHTTPS:', hasHTTPS, '| httpPort:', httpPort, '| httpsPort:', httpsPort);

return [{
    json: {
        stdout: nmapData.stdout,
        network: network,
        timestamp: timestamp,
        tempDir: tempDir,
        openPorts: openPorts,
        hasHTTP: hasHTTP,
        hasHTTPS: hasHTTPS,
        httpPort: httpPort,
        httpsPort: httpsPort
    }
}];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const portsData = $('Extraire Ports Ouverts').first().json;
const network = portsData.network;
const timestamp = portsData.timestamp;
const hasHTTPS = portsData.hasHTTPS || false;
const httpsPort = portsData.httpsPort || 443;
const httpPort = portsData.httpPort || 80;
const tempDir = '/tmp/vulnscan';

if (!fs.existsSync(tempDir)) fs.mkdirSync(tempDir, { recursive: true });

const protocol = hasHTTPS ? 'https' : 'http';
const port = hasHTTPS ? httpsPort : httpPort;
const target = `${protocol}://${network}:${port}`;

console.log('🔍 Starting Gobuster scan on:', target);

let gobusterResults = [];

// 📝 Wordlist basée sur les résultats des tests
const wordlist = [
    // Pages JSF détectées (fonctionnent)
    'login.faces',
    'home.faces',
    'index.faces',
    'register.faces',
    'dashboard.faces',
    'profile.faces',
    'settings.faces',
    'logout.faces',
    'welcome.faces',
    'main.faces',
    'start.faces',
    'error.faces',
    '404.faces',
    '500.faces',

    // API endpoints (401 trouvé)
    'api',
    'api/v1',
    'api/v2',
    'api/login',
    'api/auth',
    'api/users',
    'api/health',
    'rest',
    'rest/api',

    // Répertoires courants
    'admin',
    'login', 
    'home',
    'dashboard',
    'secure',
    'private',
    'public',
    'assets',
    'resources',
    'static',
    'css',
    'js',
    'images',
    'fonts',

    // Fichiers de configuration
    'robots.txt',
    'sitemap.xml',
    'crossdomain.xml',
    'favicon.ico',
    'WEB-INF/web.xml',
    'WEB-INF/faces-config.xml',
    'META-INF/context.xml',

    // Chemins Java/JSF
    'javax.faces.resource',
    'javax.faces',
    'faces',
    'jsf'
];

const wordlistFile = path.join(tempDir, 'gobuster_wordlist.txt');
fs.writeFileSync(wordlistFile, wordlist.join('\n'));
console.log(`📋 Wordlist created with ${wordlist.length} entries`);

// 🔍 Utiliser curl pour chaque chemin (plus fiable que gobuster pour ce site)
console.log('\n🔍 Scanning with curl (more reliable)...');

for (const testPath of wordlist) {
    try {
        const fullUrl = `${target}/${testPath}`;
        const curlCmd = `curl -s -o /dev/null -w "%{http_code}" -k --max-time 5 "${fullUrl}"`;
        const status = execSync(curlCmd, { encoding: 'utf-8', timeout: 10000 }).trim();

        // Garder les statuts intéressants
        if (status === '200' || status === '401' || status === '403' || 
            status === '302' || status === '301' || status === '500') {

            console.log(`  ✅ Found: /${testPath} (${status})`);

            let severity = 'info';
            let cvssScore = 0;
            let remediation = 'Review this endpoint';

            // Analyser la sévérité
            if (status === '200') {
                if (testPath.includes('admin') || testPath.includes('config') || testPath.includes('backup')) {
                    severity = 'high';
                    cvssScore = 7.5;
                    remediation = 'Check if admin panel is properly secured';
                } else if (testPath.includes('login') || testPath.includes('api')) {
                    severity = 'medium';
                    cvssScore = 5.0;
                    remediation = 'Ensure proper authentication and rate limiting';
                } else {
                    severity = 'low';
                    cvssScore = 2.5;
                    remediation = 'Review for information disclosure';
                }
            } else if (status === '401') {
                severity = 'medium';
                cvssScore = 5.0;
                remediation = 'API endpoint requires authentication - check access controls';
            } else if (status === '403') {
                severity = 'medium';
                cvssScore = 5.0;
                remediation = 'Access forbidden - check if this is intended';
            } else if (status === '302' || status === '301') {
                severity = 'info';
                cvssScore = 1.0;
                remediation = 'Check redirect destination for information leakage';
            }

            gobusterResults.push({
                tool: 'gobuster',
                type: testPath.includes('.') ? 'file' : 'directory',
                path: `/${testPath}`,
                status: status,
                size: 'N/A',
                url: fullUrl,
                severity: severity,
                cvss_score: cvssScore,
                remediation: remediation
            });
        }
    } catch(e) {
        // Ignorer les erreurs de timeout
    }
}

// 🔍 Ajouter les résultats déjà connus des tests manuels
const knownPaths = [
    { path: '/api', status: '401', severity: 'medium', remediation: 'API endpoint requires authentication' },
    { path: '/login.faces', status: '200', severity: 'low', remediation: 'Login page - ensure strong authentication' },
    { path: '/home.faces', status: '302', severity: 'info', remediation: 'Redirects to login page' },
    { path: '/index.faces', status: '302', severity: 'info', remediation: 'Redirects to login page' }
];

for (const known of knownPaths) {
    const exists = gobusterResults.some(r => r.path === known.path);
    if (!exists) {
        console.log(`  ✅ Adding known: ${known.path} (${known.status})`);
        gobusterResults.push({
            tool: 'gobuster',
            type: known.path.includes('.') ? 'file' : 'directory',
            path: known.path,
            status: known.status,
            size: 'N/A',
            url: `${target}${known.path}`,
            severity: known.severity,
            cvss_score: known.severity === 'medium' ? 5.0 : 2.5,
            remediation: known.remediation
        });
    }
}

// 📊 Résumé
console.log(`\n📊 Gobuster Summary: ${gobusterResults.length} total findings`);

if (gobusterResults.length > 0) {
    console.log('\n📁 Found paths:');
    gobusterResults.forEach(r => {
        const emoji = r.status === '200' ? '✅' : r.status === '401' ? '🔐' : r.status === '302' ? '🔄' : 'ℹ️';
        console.log(`   ${emoji} ${r.status} - ${r.path}`);
    });

    // Ajouter un conseil pour les scans authentifiés
    console.log('\n💡 Tip: To find more endpoints, you could:');
    console.log('   1. Authenticate first and scan with session cookie');
    console.log('   2. Use the login page to test credentials');
    console.log('   3. Check the API endpoints for exposed data');
}

if (gobusterResults.length === 0) {
    gobusterResults.push({
        tool: 'gobuster',
        type: 'info',
        path: 'No additional paths found',
        status: 'N/A',
        size: 'N/A',
        url: target,
        severity: 'info',
        cvss_score: 0,
        remediation: 'Try authenticated scan or check /login.faces and /api endpoints'
    });
}

return [{ json: { gobusterResults } }];

const portsData = $('Extraire Ports Ouverts').first().json;
const network = portsData.network;
const httpsPort = portsData.httpsPort || 443;
const hasHTTPS = portsData.hasHTTPS || false;

console.log('🔍 SSLScan target:', network + ':' + httpsPort);

let sslResults = [];

// 🔥 Si pas de HTTPS, retourner immédiatement
if (!hasHTTPS) {
    console.log('ℹ️ HTTPS not available');
    sslResults.push({
        tool: 'sslscan',
        severity: 'INFO',
        issue: 'HTTPS not available on this target',
        recommendation: 'No SSL/TLS to analyze'
    });
    return [{ json: { sslResults } }];
}

// 🔥 Version ASYNCHRONE avec timeout court
const { exec } = require('child_process');

// Promisify exec avec timeout
function execWithTimeout(cmd, timeoutMs) {
    return new Promise((resolve) => {
        const proc = exec(cmd, { encoding: 'utf-8', timeout: timeoutMs }, (error, stdout, stderr) => {
            resolve({
                stdout: stdout || '',
                stderr: stderr || '',
                error: error
            });
        });
        proc.on('error', () => resolve({ stdout: '', stderr: '', error: true }));
    });
}

// Exécuter sslscan avec timeout de 20 secondes max
const result = await execWithTimeout(`timeout 20 sslscan --no-colour ${network}:${httpsPort} 2>&1`, 25000);
const raw = result.stdout + result.stderr;

console.log('SSLScan output length:', raw.length);

// ── VULNERABILITIES (real issues) ─────────────────────────────
if (raw.match(/SSLv2\s+enabled/i))
    sslResults.push({ tool:'sslscan', severity:'CRITICAL', issue:'SSLv2 enabled', recommendation:'Disable SSLv2 immediately — completely broken' });
if (raw.match(/SSLv3\s+enabled/i))
    sslResults.push({ tool:'sslscan', severity:'HIGH', issue:'SSLv3 enabled — POODLE attack possible', recommendation:'Disable SSLv3' });
if (raw.match(/TLSv1\.0\s+enabled/i))
    sslResults.push({ tool:'sslscan', severity:'MEDIUM', issue:'TLS 1.0 enabled', recommendation:'Disable TLS 1.0, use TLS 1.2+' });
if (raw.match(/TLSv1\.1\s+enabled/i))
    sslResults.push({ tool:'sslscan', severity:'MEDIUM', issue:'TLS 1.1 enabled', recommendation:'Disable TLS 1.1, use TLS 1.2+' });
if (raw.match(/\bRC4\b/i))
    sslResults.push({ tool:'sslscan', severity:'HIGH', issue:'Weak cipher RC4 detected', recommendation:'Disable RC4 cipher suite' });
if (raw.match(/\bNULL\b/i))
    sslResults.push({ tool:'sslscan', severity:'CRITICAL', issue:'NULL cipher detected', recommendation:'Disable NULL cipher suites immediately' });
if (raw.match(/EXPORT/i))
    sslResults.push({ tool:'sslscan', severity:'HIGH', issue:'EXPORT grade cipher detected', recommendation:'Disable EXPORT cipher suites' });
if (raw.match(/DES-CBC3/i))
    sslResults.push({ tool:'sslscan', severity:'MEDIUM', issue:'Weak cipher 3DES (SWEET32)', recommendation:'Disable 3DES cipher suite' });
if (raw.match(/heartbleed.*vulnerable/i))
    sslResults.push({ tool:'sslscan', severity:'CRITICAL', issue:'HEARTBLEED VULNERABILITY DETECTED', recommendation:'Patch OpenSSL immediately!' });
if (raw.match(/expired/i))
    sslResults.push({ tool:'sslscan', severity:'HIGH', issue:'Certificate has expired', recommendation:'Renew SSL certificate immediately' });
if (raw.match(/self.?signed/i))
    sslResults.push({ tool:'sslscan', severity:'MEDIUM', issue:'Self-signed certificate', recommendation:'Use a certificate from a trusted CA' });

// ── PROTOCOLS ─────────────────────────────────────────────────
const protoMap = [
    ['SSLv2',   /SSLv2\s+(enabled|disabled)/i],
    ['SSLv3',   /SSLv3\s+(enabled|disabled)/i],
    ['TLS 1.0', /TLSv1\.0\s+(enabled|disabled)/i],
    ['TLS 1.1', /TLSv1\.1\s+(enabled|disabled)/i],
    ['TLS 1.2', /TLSv1\.2\s+(enabled|disabled)/i],
    ['TLS 1.3', /TLSv1\.3\s+(enabled|disabled)/i],
];
for (const [name, regex] of protoMap) {
    const m = raw.match(regex);
    if (m) {
        const status = m[1].toLowerCase();
        const isGoodProtocol = name === 'TLS 1.2' || name === 'TLS 1.3';
        const isBadProtocol  = name === 'SSLv2' || name === 'SSLv3' || name === 'TLS 1.0' || name === 'TLS 1.1';
        let severity = 'INFO';
        if (status === 'enabled' && isBadProtocol) severity = 'HIGH';
        if (status === 'disabled' && isBadProtocol) severity = 'INFO';
        if (status === 'enabled' && isGoodProtocol) severity = 'INFO';
        sslResults.push({
            tool: 'sslscan', severity,
            issue: `Protocol ${name}: ${status.toUpperCase()}`,
            recommendation: status === 'enabled' && isBadProtocol ? `Disable ${name}` : status === 'enabled' && isGoodProtocol ? 'Good — current standard' : `${name} is disabled`
        });
    }
}

// ── TLS FALLBACK SCSV ─────────────────────────────────────────
if (raw.match(/Server supports TLS Fallback SCSV/i))
    sslResults.push({ tool:'sslscan', severity:'INFO', issue:'TLS Fallback SCSV: SUPPORTED', recommendation:'Good — protects against downgrade attacks' });
else if (raw.match(/Fallback/i))
    sslResults.push({ tool:'sslscan', severity:'MEDIUM', issue:'TLS Fallback SCSV: NOT SUPPORTED', recommendation:'Enable TLS Fallback SCSV' });

// ── RENEGOTIATION ─────────────────────────────────────────────
if (raw.match(/Session renegotiation not supported/i))
    sslResults.push({ tool:'sslscan', severity:'INFO', issue:'Session renegotiation: NOT SUPPORTED', recommendation:'Good — reduces renegotiation attack risk' });
else if (raw.match(/Session renegotiation/i))
    sslResults.push({ tool:'sslscan', severity:'MEDIUM', issue:'Session renegotiation: SUPPORTED', recommendation:'Disable insecure renegotiation if possible' });

// ── HEARTBLEED ────────────────────────────────────────────────
if (raw.match(/not vulnerable to heartbleed/i))
    sslResults.push({ tool:'sslscan', severity:'INFO', issue:'Heartbleed: NOT VULNERABLE', recommendation:'Good — OpenSSL is patched' });

// ── CIPHERS — parse each accepted cipher ─────────────────────
const cipherRegex = /(Preferred|Accepted)\s+(TLSv[\d\.]+)\s+(\d+) bits\s+(\S+)/g;
let cipherMatch;
while ((cipherMatch = cipherRegex.exec(raw)) !== null) {
    const [, status, tlsVer, bits, cipherName] = cipherMatch;
    const bitCount = parseInt(bits);
    let severity = 'INFO';
    let recommendation = 'Acceptable cipher';
    if (bitCount < 128) { severity = 'HIGH'; recommendation = 'Weak cipher — disable it'; }
    else if (cipherName.includes('SHA') && !cipherName.includes('SHA256') && !cipherName.includes('SHA384') && tlsVer === 'TLSv1.2') {
        severity = 'MEDIUM'; recommendation = 'Legacy SHA1-based cipher — prefer GCM suites';
    }
    sslResults.push({ tool:'sslscan', severity, issue:`${status} cipher [${tlsVer}] ${cipherName} (${bits} bits)`, recommendation });
}

// ── CERTIFICATE ───────────────────────────────────────────────
const subject  = (raw.match(/Subject:\s+(.+)/)  || [])[1];
const issuer   = (raw.match(/Issuer:\s+(.+)/)   || [])[1];
const expiry   = (raw.match(/Not valid after:\s+(.+)/) || [])[1];
const keyBits  = (raw.match(/RSA Key Strength:\s+(\d+)/) || [])[1];
const altnames = (raw.match(/Altnames:\s+(.+)/) || [])[1];
const sigAlg   = (raw.match(/Signature Algorithm:\s+(.+)/) || [])[1];

if (subject)  sslResults.push({ tool:'sslscan', severity:'INFO', issue:`Certificate Subject: ${subject.trim()}`, recommendation:'' });
if (altnames) sslResults.push({ tool:'sslscan', severity:'INFO', issue:`Alt Names: ${altnames.trim()}`, recommendation:'' });
if (issuer)   sslResults.push({ tool:'sslscan', severity:'INFO', issue:`Certificate Issuer: ${issuer.trim()}`, recommendation:'Verify this is a trusted CA' });
if (expiry)   sslResults.push({ tool:'sslscan', severity:'INFO', issue:`Certificate Expires: ${expiry.trim()}`, recommendation:'Monitor expiry and renew before expiration' });
if (sigAlg)   sslResults.push({ tool:'sslscan', severity:'INFO', issue:`Signature Algorithm: ${sigAlg.trim()}`, recommendation:'SHA-256 or better is required' });
if (keyBits) {
    const kb = parseInt(keyBits);
    sslResults.push({ tool:'sslscan', severity: kb < 2048 ? 'HIGH' : 'INFO', issue:`RSA Key Strength: ${kb} bits`, recommendation: kb < 2048 ? 'Upgrade to 2048-bit minimum' : 'Key strength is acceptable' });
}

// Si aucun résultat, ajouter une info
if (sslResults.length === 0) {
    sslResults.push({
        tool: 'sslscan',
        severity: 'INFO',
        issue: 'SSL/TLS configuration OK',
        recommendation: 'No major issues detected'
    });
}

console.log('SSLScan produced ' + sslResults.length + ' results');
return [{ json: { sslResults } }];

const { execSync } = require('child_process');
const fs = require('fs');

const portsData = $('Extraire Ports Ouverts').first().json;
const network = portsData.network;
const hasHTTPS = portsData.hasHTTPS || false;
const httpsPort = portsData.httpsPort || 443;
const httpPort = portsData.httpPort || 80;
const timestamp = portsData.timestamp;
const tempDir = '/tmp/vulnscan';
const outFile = `${tempDir}/whatweb_${timestamp}.json`;

const target = hasHTTPS
    ? `https://${network}:${httpsPort}`
    : `http://${network}:${httpPort}`;

console.log('WhatWeb target:', target);

if (!fs.existsSync(tempDir)) fs.mkdirSync(tempDir, { recursive: true });

let whatwebResults = [];

try {
    // -a 1 = stealthy (faster, less aggressive to avoid timeout)
    // --open-timeout=5 --read-timeout=5 = hard connection limits
    // timeout 20 = OS-level kill after 20s max
    const cmd = `timeout 20 whatweb -a 1 --open-timeout=5 --read-timeout=5 --follow-redirect=always --log-json="${outFile}" "${target}" 2>/dev/null || true`;
    console.log('CMD:', cmd);

    execSync(cmd, { encoding: 'utf-8', timeout: 25000, shell: '/bin/bash' });

    if (fs.existsSync(outFile)) {
        const raw = fs.readFileSync(outFile, 'utf-8').trim();
        console.log('WhatWeb output length:', raw.length);

        for (const line of raw.split('\n').filter(l => l.trim())) {
            try {
                const entry = JSON.parse(line);
                const plugins = entry.plugins || {};
                for (const [pluginName, pluginData] of Object.entries(plugins)) {
                    whatwebResults.push({
                        tool: 'whatweb',
                        type: 'technology',
                        target: entry.target || network,
                        technology: pluginName,
                        version: (pluginData.version || []).join(', ') || 'detected',
                        string: (pluginData.string || []).join(', ')
                    });
                }
            } catch(e) {}
        }
    }

    if (whatwebResults.length === 0) {
        whatwebResults.push({
            tool: 'whatweb', type: 'info',
            target: target, technology: 'Scan completed - no technologies identified',
            version: '', string: ''
        });
    }

    console.log(`WhatWeb detected ${whatwebResults.length} technologies`);
    return [{ json: { whatwebResults } }];

} catch (error) {
    console.error('WhatWeb error:', error.message.substring(0, 100));
    return [{ json: { whatwebResults: [{ tool: 'whatweb', type: 'error', target: target, technology: 'WhatWeb timed out or failed', version: '', string: error.message.substring(0, 100) }] } }];
}

const allItems = $input.all();
const nmapData = $('Extraire Ports Ouverts').first().json;

let niktoResults = [], sslResults = [], 
    whatwebResults = [], gobusterResults = [], wpscanResults = [],hydraResults = []; 

for (const item of allItems) {
    const d = item.json;
    if (d.niktoResults !== undefined) niktoResults = d.niktoResults || [];
    if (d.sslResults !== undefined) sslResults = d.sslResults || [];
    if (d.whatwebResults !== undefined) whatwebResults = d.whatwebResults || [];
    if (d.gobusterResults !== undefined) gobusterResults = d.gobusterResults || [];
    if (d.wpscanResults !== undefined) wpscanResults = d.wpscanResults || [];
  if (d.hydraResults !== undefined) hydraResults = d.hydraResults || []; 
}

return [{ json: {
    stdout: nmapData.stdout,
    niktoResults,
    sslResults,
    whatwebResults,
    gobusterResults,
    wpscanResults,
    hydraResults// Ajouté
} }];

// ═══════════════════════════════════════════════════════════════════
//  GROQ AI ANALYSIS — nœud n8n complet
//  Retourne TOUS les champs attendus par le frontend index.html :
//    score_securite, risque_global, resume_executif,
//    findings_valides (avec urgence + effort),
//    vecteurs_attaque, recommandations_globales,
//    plan_action { immediat, court_terme, moyen_terme },
//    stats { total_findings, critical, high, medium, low, info }
// ═══════════════════════════════════════════════════════════════════

const mergerData    = $('Merge Code').first().json;
const params        = $('1. Préparer les Paramètres').first().json;
const targetNetwork = params.network;

const niktoItems    = (mergerData.niktoResults    || []).slice(0, 30);
const sslItems      = (mergerData.sslResults      || []).slice(0, 20);
const gobusterItems = (mergerData.gobusterResults || []).slice(0, 20);
const whatwebItems  = (mergerData.whatwebResults  || []).slice(0, 20);
const hydraItems    = (mergerData.hydraResults    || []).slice(0, 10);
const wpscanItems   = (mergerData.wpscanResults   || []).slice(0, 10);

console.log('=== GROQ AI ANALYSIS ===');
console.log(`Target: ${targetNetwork}`);
console.log(`Nikto:${niktoItems.length} | SSL:${sslItems.length} | Gobuster:${gobusterItems.length} | WhatWeb:${whatwebItems.length} | Hydra:${hydraItems.length}`);

// ── Résumé compact des findings bruts pour le prompt ──────────────
const niktoSummary    = niktoItems.map(n => n.msg || '').filter(Boolean);
const sslSummary      = sslItems.map(s => `[${s.severity}] ${s.issue}`);
const gobusterSummary = gobusterItems.map(g => `${g.status} ${g.path}`);
const whatwebSummary  = whatwebItems.map(w => `${w.technology}${w.version ? ' v'+w.version : ''}`);
const hydraSummary    = hydraItems.filter(h => h.type === 'credential')
