// ── Appel API Groq ────────────────────────────────────────────────
const GROQ_API_KEY = 'VOTRE_CLE_GROQ_ICI';

// Fallback vide si Groq échoue
function buildFallback(reason) {
  return {
    score_securite: 50,
    risque_global: 'INCONNU',
    resume_executif: `Analyse IA indisponible (${reason}). Consultez les résultats bruts ci-dessous.`,
    findings_valides: [],
    stats: { total_findings: 0, critical: 0, high: 0, medium: 0, low: 0, info: 0, faux_positifs_filtres: 0 },
    vecteurs_attaque: ['Analyse manuelle requise — IA indisponible'],
    recommandations_globales: ['Relancer le scan ou vérifier la clé API Groq'],
    plan_action: { immediat: [], court_terme: [], moyen_terme: [] }
  };
}

// Calcule les stats depuis findings_valides (filet de sécurité)
function computeStats(findings) {
  const stats = { total_findings: 0, critical: 0, high: 0, medium: 0, low: 0, info: 0, faux_positifs_filtres: 0 };
  for (const f of findings) {
    if (f.faux_positif) { stats.faux_positifs_filtres++; continue; }
    stats.total_findings++;
    const sev = (f.severite || '').toUpperCase();
    if (sev === 'CRITICAL') stats.critical++;
    else if (sev === 'HIGH') stats.high++;
    else if (sev === 'MEDIUM') stats.medium++;
    else if (sev === 'LOW') stats.low++;
    else stats.info++;
  }
  return stats;
}

// Calcule le score depuis les stats (filet de sécurité)
function computeScore(stats) {
  const score = 100 - stats.critical*20 - stats.high*10 - stats.medium*5 - stats.low*2;
  return Math.max(0, Math.min(100, score));
}

// Normalise le risque_global selon le score
function normalizeRisk(risk, score) {
  const validRisks = ['CRITIQUE', 'ÉLEVÉ', 'MOYEN', 'FAIBLE'];
  const r = (risk || '').toUpperCase().trim();
  if (validRisks.includes(r)) return r;
  // Déduit depuis le score si la valeur est invalide
  if (score <= 30) return 'CRITIQUE';
  if (score <= 50) return 'ÉLEVÉ';
  if (score <= 70) return 'MOYEN';
  return 'FAIBLE';
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${GROQ_API_KEY}`
    },
    body: JSON.stringify({
      model: 'llama-3.3-70b-versatile',
      max_tokens: 6000,
      temperature: 0.1,
      response_format: { type: 'json_object' },   // force JSON mode
      messages: [
        {
          role: 'system',
          content: 'Tu es un expert en cybersécurité. Tu retournes UNIQUEMENT du JSON valide, sans markdown, sans backticks, sans texte avant ou après le JSON.'
        },
        {
          role: 'user',
          content: prompt
        }
      ]
    }),
    timeout: 90000
  });

  const rawText = response.choices[0].message.content;
  console.log('Groq response length:', rawText.length);

  // Nettoyage défensif des backticks au cas où
  const cleanText = rawText
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```$/,           '')
    .trim();

  let aiAnalysis = JSON.parse(cleanText);

  // ── Filets de sécurité ─────────────────────────────────────────
  const findings = aiAnalysis.findings_valides || [];

  // 1. Recalcule les stats si absentes ou à zéro
  if (!aiAnalysis.stats || aiAnalysis.stats.total_findings === 0 && findings.length > 0) {
    aiAnalysis.stats = computeStats(findings);
  }

  // 2. Recalcule le score si absent
  if (!aiAnalysis.score_securite || aiAnalysis.score_securite === 0) {
    aiAnalysis.score_securite = computeScore(aiAnalysis.stats);
  }

  // 3. Normalise le risque_global
  aiAnalysis.risque_global = normalizeRisk(
    aiAnalysis.risque_global,
    aiAnalysis.score_securite
  );

  // 4. Assure urgence + effort sur chaque finding
  const urgenceMap = { CRITICAL:'Immédiate', HIGH:'Sous 24h', MEDIUM:'Cette semaine', LOW:'Ce mois', INFO:'À planifier' };
  const effortMap  = { CRITICAL:'Élevé',    HIGH:'Moyen',    MEDIUM:'Moyen',          LOW:'Faible', INFO:'Faible' };
  for (const f of findings) {
    const sev = (f.severite || 'INFO').toUpperCase();
    f.urgence = f.urgence || urgenceMap[sev] || 'À planifier';
    f.effort  = f.effort  || effortMap[sev]  || 'Faible';
    f.cvss_score  = f.cvss_score  || 0;
    f.cvss_vector = f.cvss_vector || '';
    f.cves        = f.cves        || [];
  }

  // 5. Assure les listes de vecteurs / recommandations / plan_action
  if (!aiAnalysis.vecteurs_attaque || !aiAnalysis.vecteurs_attaque.length) {
    aiAnalysis.vecteurs_attaque = findings
      .filter(f => ['CRITICAL','HIGH'].includes((f.severite||'').toUpperCase()))
      .slice(0,5)
      .map(f => `[${f.severite}] ${f.titre} (${f.source})`);
    if (!aiAnalysis.vecteurs_attaque.length) {
      aiAnalysis.vecteurs_attaque = ['Aucun vecteur critique identifié'];
    }
  }

  if (!aiAnalysis.recommandations_globales || !aiAnalysis.recommandations_globales.length) {
    aiAnalysis.recommandations_globales = findings
      .filter(f => !f.faux_positif && f.remediation)
      .slice(0,6)
      .map(f => f.remediation);
  }

  if (!aiAnalysis.plan_action) {
    aiAnalysis.plan_action = { immediat: [], court_terme: [], moyen_terme: [] };
  }
  const plan = aiAnalysis.plan_action;
  if (!plan.immediat?.length && !plan.court_terme?.length && !plan.moyen_terme?.length) {
    for (const f of findings) {
      const sev = (f.severite||'').toUpperCase();
      const item = `${f.titre} — ${(f.remediation||'Corriger').substring(0,100)}`;
      if (sev === 'CRITICAL' && plan.immediat.length < 5)    plan.immediat.push(item);
      else if (sev === 'HIGH' && plan.court_terme.length < 5) plan.court_terme.push(item);
      else if (plan.moyen_terme.length < 5)                   plan.moyen_terme.push(item);
    }
  }

  // ── Logs ──────────────────────────────────────────────────────
  console.log(`✅ Score: ${aiAnalysis.score_securite}/100`);
  console.log(`✅ Risque: ${aiAnalysis.risque_global}`);
  console.log(`✅ Findings: ${findings.length} (critical:${aiAnalysis.stats.critical} high:${aiAnalysis.stats.high})`);
  console.log(`✅ Vecteurs: ${aiAnalysis.vecteurs_attaque.length}`);
  console.log(`✅ Recommandations: ${aiAnalysis.recommandations_globales.length}`);

  return [{ json: {
    ...mergerData,
    aiAnalysis,
    aiSuccess: true
  }}];

} catch(error) {
  console.error('❌ Groq API error:', error.message);
  return [{ json: {
    ...mergerData,
    aiAnalysis: buildFallback(error.message.substring(0, 80)),
    aiSuccess: false,
    aiError: error.message
  }}];
}

const raw = $input.first().json;
