let services = [];
const hosts = nmapJson.host || [];

for (const host of hosts) {
    const ip = host.address?.[0]?.addr || 'unknown';
    const ports = host.ports?.port || [];

    for (const portObj of ports) {
        if (portObj.state?.state !== 'open') continue;
        const serviceObj = portObj.service || {};

        let cpe = '';
        if (Array.isArray(serviceObj.cpe) && serviceObj.cpe.length > 0) {
            const rawCpe = serviceObj.cpe[0];
            if (rawCpe.startsWith('cpe:/')) {
                cpe = 'cpe:2.3:' + rawCpe.slice(5).replace(/\//g, ':');
                const parts = cpe.split(':');
                while (parts.length < 13) parts.push('*');
                cpe = parts.slice(0, 13).join(':');
            } else {
                cpe = rawCpe;
            }
        }

        services.push({
            ip, port: portObj.portid, protocol: portObj.protocol,
            service: serviceObj.name || 'unknown',
            product: serviceObj.product || '',
            version: serviceObj.version || '',
            cpe,
            serviceKey: `${ip}:${portObj.portid}`
        });
    }
}

console.log(`✓ Parsed ${services.length} open services`);
return [{ json: { services } }];

const services = $input.first().json.services;
const enriched = [];

console.log('=== CVE ENRICHMENT START ===');
console.log(`Processing ${services.length} services`);

for (let i = 0; i < services.length; i++) {
    const service = services[i];
    const base = { ...service };

    if (!base.cpe || base.cpe.trim() === '' || base.cpe === ':') {
        enriched.push({ ...base, cveId: 'N/A', cveSummary: 'No CPE available', cvssScore: 0, severity: 'INFO' });
        continue;
    }

    try {
        const vendor = base.cpe.split(':')[3] || '';
        const product = base.cpe.split(':')[4] || '';
        const version = base.cpe.split(':')[5] || '';

        let apiUrl = version && version !== '*'
            ? `https://services.nvd.nist.gov/rest/json/cves/2.0?cpeName=${encodeURIComponent(base.cpe)}&resultsPerPage=20`
            : `https://services.nvd.nist.gov/rest/json/cves/2.0?keywordSearch=${encodeURIComponent(vendor + ' ' + product)}&resultsPerPage=20`;

        console.log(`[${i+1}/${services.length}] Querying: ${base.cpe}`);

        const response = await this.helpers.httpRequest({
            method: 'GET',
            url: apiUrl,
            timeout: 30000,
            headers: { 'User-Agent': 'n8n-vulnerability-scanner/2.0' }
        });

        const vulnerabilities = response.vulnerabilities || [];
        console.log(`-> Found ${vulnerabilities.length} CVEs`);

        if (vulnerabilities.length === 0) {
            enriched.push({ ...base, cveId: 'N/A', cveSummary: 'No known vulnerabilities found', cvssScore: 0, severity: 'INFO' });
        } else {
            for (const vuln of vulnerabilities) {
                const cve = vuln.cve || {};
                const cveId = cve.id || 'UNKNOWN';
                const cveSummary = (cve.descriptions || []).find(d => d.lang === 'en')?.value || 'No description';
                const metrics = cve.metrics || {};
                const metricV31 = metrics.cvssMetricV31?.[0];
                const metricV30 = metrics.cvssMetricV30?.[0];
                const metricV2 = metrics.cvssMetricV2?.[0];
                const bestMetric = metricV31 || metricV30 || metricV2;
                const cvssData = bestMetric?.cvssData || {};
                const cvssScore = cvssData.baseScore || 0;
                const severity = cvssData.baseSeverity || metricV2?.baseSeverity || 'UNKNOWN';
                const publishedDate = cve.published || 'N/A';

                enriched.push({ ...base, cveId, cveSummary, cvssScore, severity, publishedDate });
            }
        }

    } catch (error) {
        console.error(`Error: ${error.message}`);
        enriched.push({ ...base, cveId: 'N/A', cveSummary: `API Error: ${error.message}`, cvssScore: 0, severity: 'ERROR' });
    }

    if (i < services.length - 1) {
        console.log('Waiting 6s...');
        await new Promise(r => setTimeout(r, 6000));
    }
}

console.log(`=== CVE ENRICHMENT COMPLETE: ${enriched.length} results ===`);
return [{ json: { enriched } }];

