if (openPorts.includes(21))   servicesToScan.push({ service: 'ftp',        port: 21,        ext: 'ftp',        timeout: 30000 });
if (openPorts.includes(3306)) servicesToScan.push({ service: 'mysql',      port: 3306,      ext: 'mysql',      timeout: 30000 });
if (openPorts.includes(5432)) servicesToScan.push({ service: 'postgres',   port: 5432,      ext: 'postgres',   timeout: 30000 });
if (openPorts.includes(3389)) servicesToScan.push({ service: 'rdp',        port: 3389,      ext: 'rdp',        timeout: 60000 });
if (openPorts.includes(23))   servicesToScan.push({ service: 'telnet',     port: 23,        ext: 'telnet',     timeout: 30000 });

// HTTP / HTTPS - avec gestion des formulaires
if (hasHTTPS && openPorts.includes(httpsPort)) {
    servicesToScan.push({ 
        service: 'https-get', 
        port: httpsPort, 
        ext: 'https', 
        path: '/',
        timeout: 30000
    });
