        port: httpPort,  
        ext: 'http',  
        path: '/',
        timeout: 30000
    });
}

console.log('🎯 Services to brute-force:', servicesToScan.map(s => s.service).join(', ') || 'none');

if (servicesToScan.length === 0) {
    hydraResults.push({ 
        tool: 'hydra', 
        type: 'info', 
        id: 'NO_SERVICES',
        severity: 'info', 
        description: 'No brute-forceable services found on open ports', 
        url: network 
    });
    return [{ json: { hydraResults } }];
}

// 🔑 Scanner chaque service
for (const target of servicesToScan) {
    console.log(`🔑 Brute-forcing ${target.service} on port ${target.port}...`);
    const outFile = `${baseOutput}.${target.ext}`;

    let cmd = '';

    // Construire la commande hydra selon le service
    if (target.service === 'https-get') {
        cmd = `hydra -L ${userFile} -P ${passFile} -o ${outFile} -f -v -I -s ${target.port} https-get://${network}${target.path}`;
    } else if (target.service === 'http-get') {
        cmd = `hydra -L ${userFile} -P ${passFile} -o ${outFile} -f -v -I http-get://${network}:${target.port}${target.path}`;
    } else if (target.service === 'https-post-form') {
        // Test pour formulaires POST (login.faces, etc.)
        cmd = `hydra -L ${userFile} -P ${passFile} -o ${outFile} -f -v -I -s ${target.port} https-post-form://${network}${target.path}:${target.formData}:Invalid`;
    } else {
        cmd = `hydra -L ${userFile} -P ${passFile} ${target.service}://${network}:${target.port} -t 4 -o ${outFile} -f -v -I`;
    }

    console.log('💻 CMD:', cmd.substring(0, 150) + '...');

    try {
        await execPromise(cmd, { timeout: target.timeout || 120000, shell: '/bin/bash' });
    } catch(e) {
        // Hydra retourne un code d'erreur même si des credentials sont trouvés
        console.log(`📊 ${target.service} scan completed`);
    }

    // Lire les résultats
    if (fs.existsSync(outFile)) {
        const content = fs.readFileSync(outFile, 'utf-8');
        console.log(`📄 ${target.service} output length: ${content.length} chars`);

        for (const line of content.split('\n')) {
            // Format standard Hydra
            let match = line.match(/host:\s*(\S+)\s+login:\s*(\S+)\s+password:\s*(.+)/i);

            // Format alternatif
            if (!match) {
                match = line.match(/\[.*?\]\s+host:\s*(\S+)\s+login:\s*(\S+)\s+pass:\s*(.+)/i);
            }

            if (match) {
                const username = match[2];
                const password = match[3].trim();

                hydraResults.push({
                    tool: 'hydra',
                    type: 'credential',
                    service: target.service,
                    port: target.port,
                    host: match[1],
                    username: username,
                    password: password,
                    severity: 'critical',
                    description: `Weak credentials found for ${target.service} on port ${target.port}`,
                    remediation: `⚠️ Change password for '${username}' immediately. Use a strong, unique password with at least 12 characters, mix of letters, numbers and symbols.`
                });

                console.log(`✅ Found credential: ${username}:${password}`);
            }
        }
    }
}

// Nettoyer les fichiers temporaires
try { 
    fs.unlinkSync(passFile); 
    fs.unlinkSync(userFile); 
